text:
I'm sorry to say I missed this PR when it first arrived and unfortunately it looks like it was missed upstream too as the change isn't in the 18 release branch despite being merged to main over a month ago.  I tried a quick back port patch at it didn't apply to the llvm18 tree which might explain why it didn't make it into the branch.

This looks like it's the equivalent for the LLVM 18 codebase, but I'm not in a position to test it easily.


--- openmp/runtime/src/z_Linux_util.cpp.orig
+++ openmp/runtime/src/z_Linux_util.cpp
@@ -2129,10 +2129,10 @@
   // We pass from number of vm entry's semantic
   // to size of whole entry map list.
   lstsz = lstsz * 4 / 3;
-  buf = reinterpret_cast<char *>(kmpc_malloc(lstsz));
+  buf = reinterpret_cast<char *>(KMP_INTERNAL_MALLOC(lstsz));
   rc = sysctl(mib, 4, buf, &lstsz, NULL, 0);
   if (rc < 0) {
-    kmpc_free(buf);
+    KMP_INTERNAL_FREE(buf);
     return 0;
   }

@@ -2156,7 +2156,7 @@
     }
     lw += cursz;
   }
-  kmpc_free(buf);
+  KMP_INTERNAL_FREE(buf);

 #elif KMP_OS_DARWIN
